sql:
SELECT yield_value
FROM yield_curves
WHERE series_id = '0' AND date = '1960-01-01';

SELECT value 
FROM treasury_bills 
WHERE series_id = 'TB3MS';

SELECT AVG(value) AS average_value
FROM treasury_bills
WHERE maturity = '3m' AND issue_date LIKE '1960%';

